import os
from pathlib import Path

# Get the absolute path to resume.md in the project directory
RESUME_FILE_PATH = str(Path.cwd() / 'resume.md')

def get_fixed_resume_content() -> str:
    """Read and return the resume content from resume.md file."""
    try:
        with open(RESUME_FILE_PATH, 'r', encoding='utf-8') as f:
            content = f.read()
        return content
    except FileNotFoundError:
        return f"Error: resume.md file not found at {RESUME_FILE_PATH}"
    except Exception as e:
        return f"Error reading resume: {str(e)}"

def save_fixed_resume_content(updated_resume: str) -> str:
    """Save the updated resume content to resume.md file."""
    try:
        with open(RESUME_FILE_PATH, 'w', encoding='utf-8') as f:
            f.write(updated_resume)
        return f"Resume updated successfully and saved to {RESUME_FILE_PATH}"
    except Exception as e:
        return f"Error saving resume: {str(e)}"

